1	---------------------------------------------------------------------------------------------------
2	-- Copyright (c) 2018 by Paul Scherrer Institute, Switzerland
3	-- Copyright (c) 2025 by Oliver Bruendler
4	-- Authors: Oliver Bruendler
5	---------------------------------------------------------------------------------------------------
6	
7	---------------------------------------------------------------------------------------------------
8	-- Description
9	---------------------------------------------------------------------------------------------------
10	-- This entity implements a CIC decimator. It supports one or multiple channels (time-division-multiplexed).
11	-- The decimation ratio can either be configurable or fixed.
12	--
13	-- Documentation:
14	-- https://github.com/open-logic/open-logic/blob/main/doc/fix/olo_fix_cic_dec_tdm.md
15	--
16	-- Note: The link points to the documentation of the latest release. If you
17	--       use an older version, the documentation might not match the code.
18	
19	---------------------------------------------------------------------------------------------------
20	-- Libraries
21	---------------------------------------------------------------------------------------------------
22	library ieee;
23	    use ieee.std_logic_1164.all;
24	    use ieee.numeric_std.all;
25	    use ieee.math_real.all;
26	
27	library work;
28	    use work.olo_base_pkg_math.all;
29	    use work.olo_base_pkg_string.all;
30	    use work.olo_base_pkg_array.all;
31	    use work.en_cl_fix_pkg.all;
32	    use work.olo_fix_pkg.all;
33	
34	---------------------------------------------------------------------------------------------------
35	-- Entity
36	---------------------------------------------------------------------------------------------------
37	entity olo_fix_cic_dec_tdm is
38	    generic (
39	        Channels_g        : positive := 1;
40	        Order_g           : positive range 2 to 32;
41	        Ratio_g           : positive;
42	        FixedRatio_g      : boolean  := true;
43	        DiffDelay_g       : positive := 1;
44	        InFmt_g           : string;
45	        OutFmt_g          : string;
46	        GainCorrCoefFmt_g : string   := "(0,1,16)";
47	        Round_g           : string   := FixRound_NonSymPos_c;
48	        Saturate_g        : string   := FixSaturate_Warn_c;
49	        -- Resource control generics
50	        RamBehavior_g     : string   := "RBW";
51	        RamStyle_g        : string   := "auto";
52	        Resource_g        : string   := "AUTO"
53	    );
54	    port (
55	        -- Control Signals
56	        Clk          : in    std_logic;
57	        Rst          : in    std_logic;
58	
59	        -- Configuration (only change when in reset!)
60	        Cfg_Ratio    : in    std_logic_vector(log2ceil(Ratio_g) - 1 downto 0);
61	        Cfg_Shift    : in    std_logic_vector(7 downto 0);
62	        Cfg_GainCorr : in    std_logic_vector(fixFmtWidthFromStringTolerant(GainCorrCoefFmt_g) - 1 downto 0);
63	
64	        -- Input
65	        In_Valid     : in    std_logic := '1';
66	        In_Data      : in    std_logic_vector(fixFmtWidthFromString(InFmt_g) - 1 downto 0);
67	        In_Last      : in    std_logic := '0';
68	
69	        -- Output
70	        Out_Valid    : out   std_logic;
71	        Out_Data     : out   std_logic_vector(fixFmtWidthFromString(OutFmt_g) - 1 downto 0);
72	        Out_Last     : out   std_logic
73	    );
74	end entity;
75	
76	---------------------------------------------------------------------------------------------------
77	-- Architecture
78	---------------------------------------------------------------------------------------------------
79	architecture rtl of olo_fix_cic_dec_tdm is
80	
81	    -- Formats
82	    constant EntityName_c      : string      := "olo_fix_cic_dec_tdm";
83	    constant InFmt_c           : FixFormat_t := cl_fix_format_from_string(InFmt_g);
84	    constant OutFmt_c          : FixFormat_t := cl_fix_format_from_string(OutFmt_g);
85	    constant GainCorrCoefFmt_c : FixFormat_t := fixFmtFromStringTolerant(GainCorrCoefFmt_g);
86	
87	    -- Constants
88	    constant MaxCicGain_c    : real    := (real(Ratio_g) * real(DiffDelay_g))**real(Order_g);
89	    constant MaxCicAddBits_c : natural := log2ceil(MaxCicGain_c - 0.1);
90	    -- ... WORKAROUND: Vivado does real calculations imprecisely. With the -0.1, wrong results are avoided.
91	    constant MaxShift_c      : natural     := MaxCicAddBits_c;
92	    constant AccuFmt_c       : FixFormat_t := (InFmt_c.S, InFmt_c.I + MaxCicAddBits_c, InFmt_c.F);
93	    constant DiffFmt_c       : FixFormat_t := (OutFmt_c.S, InFmt_c.I, OutFmt_c.F + Order_g + 1);
94	    constant GcInFmt_c       : FixFormat_t := (1, OutFmt_c.I, work.olo_base_pkg_math.min(OutFmt_c.F + 2, DiffFmt_c.F));
95	    constant SftFmt_c        : FixFormat_t := (AccuFmt_c.S, AccuFmt_c.I, max(AccuFmt_c.F, DiffFmt_c.F));
96	    constant RealGc_c        : real        := 2.0**real(MaxCicAddBits_c)/MaxCicGain_c;
97	
98	    constant FixedGc_c : std_logic_vector(cl_fix_width(GainCorrCoefFmt_c) - 1 downto 0) :=
99	        cl_fix_from_real(RealGc_c, GainCorrCoefFmt_c);
100	
101	    -- Types
102	    type Accus_t is array (natural range <>) of std_logic_vector(cl_fix_width(AccuFmt_c) - 1 downto 0);
103	    type Diff_t is array (natural range <>) of std_logic_vector(cl_fix_width(DiffFmt_c) - 1 downto 0);
104	
105	    -- Two Process Method
106	    type TwoProcess_r is record
107	        -- GainCorr Registers
108	        GcCoef    : std_logic_vector(cl_fix_width(GainCorrCoefFmt_c) - 1 downto 0);
109	        -- Accu Section
110	        Input_0   : std_logic_vector(cl_fix_width(InFmt_c) - 1 downto 0);
111	        VldAccu   : std_logic_vector(0 to Order_g);
112	        Accu      : Accus_t(1 to Order_g);
113	        Rcnt      : integer range 0 to Ratio_g - 1;
114	        Chcnt     : integer range 0 to Channels_g - 1;
115	        -- Diff Section
116	        DiffIn_0  : std_logic_vector(cl_fix_width(DiffFmt_c) - 1 downto 0);
117	        VldDiff   : std_logic_vector(0 to Order_g);
118	        DiffVal   : Diff_t(1 to Order_g);
119	        -- Output
120	        OutChCnt  : natural range 0 to Channels_g - 1;
121	        Outp      : std_logic_vector(cl_fix_width(OutFmt_c) - 1 downto 0);
122	        Out_Valid : std_logic;
123	        Out_Last  : std_logic;
124	    end record;
125	
126	    signal r, r_next : TwoProcess_r;
127	
128	    -- Component Connection Signals
129	    signal DiffDel      : Diff_t(0 to Order_g - 1);
130	    signal IntDel       : Accus_t(1 to Order_g);
131	    signal ShiftVld     : std_logic;
132	    signal ShiftDataOut : std_logic_vector(cl_fix_width(SftFmt_c) - 1 downto 0);
133	
134	    -- Gain Correction Signals
135	    signal CompOut    : std_logic_vector(cl_fix_width(OutFmt_c) - 1 downto 0);
136	    signal CompOutVld : std_logic;
137	
138	begin
139	
140	    -----------------------------------------------------------------------------------------------
141	    -- Assertions
142	    -----------------------------------------------------------------------------------------------
143	    assert (compareNoCase(GainCorrCoefFmt_g, "NONE") or GainCorrCoefFmt_c.I = 1)
144	        report errorMessage(EntityName_c, "Gain correction coefficient format must have 1 integer bit (or be NONE)")
145	        severity failure;
146	    assert (compareNoCase(GainCorrCoefFmt_g, "NONE") or GainCorrCoefFmt_c.S = 0)
147	        report errorMessage(EntityName_c, "Gain correction coefficient format must be unsigned (or be NONE)")
148	        severity failure;
149	
150	    -----------------------------------------------------------------------------------------------
151	    -- Combinatorial Process
152	    -----------------------------------------------------------------------------------------------
153	    p_comb : process (all) is
154	        variable v        : TwoProcess_r;
155	        variable AccuIn_v : Accus_t(1 to Order_g);
156	        variable Ratio_v  : std_logic_vector(Cfg_Ratio'range);
157	    begin
158	        -- hold variables stable
159	        v := r;
160	
161	        -- Ratio from port or constant
162	        if FixedRatio_g then
163	            Ratio_v := toUslv(Ratio_g - 1, Cfg_Ratio'length);
164	        else
165	            Ratio_v := Cfg_Ratio;
166	        end if;
167	
168	        -- *** Pipe Handling ***
169	        v.VldAccu(v.VldAccu'low + 1 to v.VldAccu'high) := r.VldAccu(r.VldAccu'low to r.VldAccu'high - 1);
170	        v.VldDiff(v.VldDiff'low + 1 to v.VldDiff'high) := r.VldDiff(r.VldDiff'low to r.VldDiff'high - 1);
171	
172	        -- *** Stage Accu 0 ***
173	        -- Input Registers
174	        v.VldAccu(0) := In_Valid;
175	        v.Input_0    := In_Data;
176	
177	        -- Select accumulator input (register for single channel, delay line other wise)
178	        if Channels_g = 1 then
179	            AccuIn_v := r.Accu;
180	        else
181	            AccuIn_v := IntDel;
182	        end if;
183	
184	        -- *** Stage Accu 1 ***
185	        -- First accumulator
186	        if r.VldAccu(0) = '1' then
187	            v.Accu(1) := cl_fix_add(AccuIn_v(1), AccuFmt_c,
188	                                    r.Input_0, InFmt_c,
189	                                    AccuFmt_c, Trunc_s, None_s);
190	        end if;
191	
192	        -- *** Accumuator Stages (2 to Order) ***
193	        for stage in 1 to Order_g - 1 loop
194	            if r.VldAccu(stage) = '1' then
195	                v.Accu(stage + 1) := cl_fix_add(AccuIn_v(stage + 1), AccuFmt_c,
196	                                                r.Accu(stage), AccuFmt_c,
197	                                                AccuFmt_c, Trunc_s, None_s);
198	            end if;
199	        end loop;
200	
201	        -- *** Stage Diff 0 ***
202	        -- Decimate
203	        v.VldDiff(0) := '0';
204	        if ShiftVld = '1' then
205	            -- channel counter
206	            if r.Chcnt = 0 then
207	                v.Chcnt := Channels_g - 1;
208	                if r.Rcnt = 0 then
209	                    v.Rcnt := fromUslv(Ratio_v);
210	                else
211	                    v.Rcnt := r.Rcnt - 1;
212	                end if;
213	            else
214	                v.Chcnt := r.Chcnt - 1;
215	            end if;
216	            -- Resample
217	            if r.Rcnt = 0 then
218	                v.VldDiff(0) := '1';
219	                v.DiffIn_0   := cl_fix_resize(ShiftDataOut, SftFmt_c, DiffFmt_c, Trunc_s, None_s);
220	            end if;
221	        end if;
222	
223	        -- *** Stage Diff 1 ***
224	        -- First differentiator
225	        if r.VldDiff(0) = '1' then
226	            -- Differentiate
227	            v.DiffVal(1) := cl_fix_sub(r.DiffIn_0, DiffFmt_c,
228	                                       DiffDel(0), DiffFmt_c,
229	                                       DiffFmt_c, Trunc_s, None_s);
230	        end if;
231	
232	        -- *** Diff Stages ***
233	        -- Differentiators
234	        for stage in 1 to Order_g - 1 loop
235	            if r.VldDiff(stage) = '1' then
236	                -- Differentiate
237	                v.DiffVal(stage + 1) := cl_fix_sub(r.DiffVal(stage), DiffFmt_c,
238	                                                   DiffDel(stage), DiffFmt_c,
239	                                                   DiffFmt_c, Trunc_s, None_s);
240	            end if;
241	        end loop;
242	
243	        if not compareNoCase(GainCorrCoefFmt_g, "NONE") then
244	            -- *** Gain Coefficient Register ***
245	            v.GcCoef := Cfg_GainCorr;
246	        end if;
247	
248	        -- *** Output Assignment ***
249	        v.Outp      := CompOut;
250	        v.Out_Valid := CompOutVld;
251	
252	        -- *** Last calculation for TDM output ***
253	        v.Out_Last := '0';
254	        if v.Out_Valid = '1' then
255	            if r.OutChCnt = Channels_g - 1 then
256	                v.Out_Last := '1';
257	                v.OutChCnt := 0;
258	            else
259	                v.OutChCnt := r.OutChCnt + 1;
260	            end if;
261	        end if;
262	
263	        -- Apply to record
264	        r_next <= v;
265	
266	    end process;
267	
268	    -----------------------------------------------------------------------------------------------
269	    -- Output Assignment
270	    -----------------------------------------------------------------------------------------------
271	    Out_Valid <= r.Out_Valid;
272	    Out_Data  <= r.Outp;
273	    Out_Last  <= r.Out_Last;
274	
275	    -----------------------------------------------------------------------------------------------
276	    -- Sequential Process
277	    -----------------------------------------------------------------------------------------------
278	    p_seq : process (Clk) is
279	    begin
280	        if rising_edge(Clk) then
281	            r <= r_next;
282	            if Rst = '1' then
283	                r.VldAccu   <= (others => '0');
284	                r.Accu      <= (others => (others => '0'));
285	                r.Rcnt      <= 0;
286	                r.Chcnt     <= Channels_g - 1;
287	                r.VldDiff   <= (others => '0');
288	                r.OutChCnt  <= 0;
289	                r.Out_Valid <= '0';
290	                r.Out_Last  <= '0';
291	            end if;
292	        end if;
293	    end process;
294	
295	    -----------------------------------------------------------------------------------------------
296	    -- Input TDM Validation
297	    -----------------------------------------------------------------------------------------------
298	    -- synthesis translate_off
299	    p_assert_in : process (Clk) is
300	        variable ChCnt_v : natural range 0 to Channels_g - 1;
301	    begin
302	        if rising_edge(Clk) then
303	            if Rst = '1' then
304	                ChCnt_v := 0;
305	            elsif In_Valid = '1' then
306	                if In_Last = '1' then
307	                    -- Only report if In_Last is asserted when NOT expected
308	                    assert ChCnt_v = Channels_g - 1
309	                        report errorMessage(EntityName_c, "In_Last asserted at channel index " & integer'image(ChCnt_v) &
310	                               " but expected at " & integer'image(Channels_g - 1))
311	                        severity error;
312	                end if;
313	
314	                if ChCnt_v = Channels_g - 1 then
315	                    ChCnt_v := 0;
316	                else
317	                    ChCnt_v := ChCnt_v + 1;
318	                end if;
319	            end if;
320	        end if;
321	    end process;
322	
323	    -- synthesis translate_on
324	
325	    -----------------------------------------------------------------------------------------------
326	    -- Component Instantiations
327	    -----------------------------------------------------------------------------------------------
328	    -- *** Gain Correction Chain ***
329	    g_gc : if not compareNoCase(GainCorrCoefFmt_g, "NONE") generate
330	        signal GcIn_0   : std_logic_vector(cl_fix_width(GcInFmt_c) - 1 downto 0);
331	        signal GcVld_0  : std_logic;
332	        signal GcCoef_0 : std_logic_vector(cl_fix_width(GainCorrCoefFmt_c) - 1 downto 0);
333	    begin
334	
335	        -- Resize
336	        i_gc_resize : entity work.olo_fix_resize
337	            generic map (
338	                AFmt_g      => to_string(DiffFmt_c),
339	                ResultFmt_g => to_string(GcInFmt_c),
340	                Round_g     => FixRound_Trunc_c,
341	                Saturate_g  => Saturate_g,
342	                RoundReg_g  => "auto",
343	                SatReg_g    => "auto"
344	            )
345	            port map (
346	                Clk        => Clk,
347	                Rst        => Rst,
348	                In_Valid   => r.VldDiff(Order_g),
349	                In_A       => r.DiffVal(Order_g),
350	                Out_Valid  => GcVld_0,
351	                Out_Result => GcIn_0
352	            );
353	
354	        -- Multiplier
355	        GcCoef_0 <= FixedGc_c when FixedRatio_g else r.GcCoef;
356	
357	        i_gc_mult : entity work.olo_fix_mult
358	            generic map (
359	                AFmt_g      => to_string(GcInFmt_c),
360	                BFmt_g      => to_string(GainCorrCoefFmt_c),
361	                ResultFmt_g => to_string(OutFmt_c),
362	                Round_g     => Round_g,
363	                Saturate_g  => Saturate_g,
364	                OpRegs_g    => 1,
365	                RoundReg_g  => "auto",
366	                SatReg_g    => "auto"
367	            )
368	            port map (
369	                Clk        => Clk,
370	                Rst        => Rst,
371	                In_Valid   => GcVld_0,
372	                In_A       => GcIn_0,
373	                In_B       => GcCoef_0,
374	                Out_Valid  => CompOutVld,
375	                Out_Result => CompOut
376	            );
377	
378	    end generate;
379	
380	    g_no_gc : if compareNoCase(GainCorrCoefFmt_g, "NONE") generate
381	
382	        i_resize_out : entity work.olo_fix_resize
383	            generic map (
384	                AFmt_g      => to_string(DiffFmt_c),
385	                ResultFmt_g => to_string(OutFmt_c),
386	                Round_g     => Round_g,
387	                Saturate_g  => Saturate_g,
388	                RoundReg_g  => "auto",
389	                SatReg_g    => "auto"
390	            )
391	            port map (
392	                Clk        => Clk,
393	                Rst        => Rst,
394	                In_Valid   => r.VldDiff(Order_g),
395	                In_A       => r.DiffVal(Order_g),
396	                Out_Valid  => CompOutVld,
397	                Out_Result => CompOut
398	            );
399	
400	    end generate;
401	
402	    -- *** Dynamic Shifter ***
403	    -- For configurable ratio, the shift is dynamic. For fixed ratio it is fixed.
404	    g_shift_conf : if not FixedRatio_g generate
405	        signal ShiftSel    : std_logic_vector(log2ceil(MaxShift_c + 1) - 1 downto 0);
406	        signal ShiftDataIn : std_logic_vector(cl_fix_width(SftFmt_c) - 1 downto 0);
407	    begin
408	
409	        ShiftSel    <= Cfg_Shift(ShiftSel'range);
410	        ShiftDataIn <= cl_fix_resize(r.Accu(Order_g), AccuFmt_c, SftFmt_c);
411	
412	        i_sft : entity work.olo_base_dyn_sft
413	            generic map (
414	                Direction_g       => "RIGHT",
415	                SelBitsPerStage_g => 4,
416	                MaxShift_g        => MaxShift_c,
417	                Width_g           => cl_fix_width(SftFmt_c),
418	                SignExtend_g      => true
419	            )
420	            port map (
421	                Clk       => Clk,
422	                Rst       => Rst,
423	                In_Valid  => r.VldAccu(Order_g),
424	                In_Shift  => ShiftSel,
425	                In_Data   => ShiftDataIn,
426	                Out_Valid => ShiftVld,
427	                Out_Data  => ShiftDataOut
428	            );
429	
430	    end generate;
431	
432	    g_shift_fixed : if FixedRatio_g generate
433	        -- Shift is combinatorial because it is pure wiring
434	        ShiftVld     <= r.VldAccu(Order_g);
435	        ShiftDataOut <= cl_fix_shift(r.Accu(Order_g), AccuFmt_c, -MaxShift_c, SftFmt_c, Trunc_s, None_s);
436	    end generate;
437	
438	    -- *** Diff-delays ***
439	    g_diffdel : for stage in 0 to Order_g - 1 generate
440	        signal DiffDelIn : std_logic_vector(cl_fix_width(DiffFmt_c) - 1 downto 0);
441	        signal DiffVldIn : std_logic;
442	    begin
443	        DiffDelIn <= r.DiffIn_0 when stage = 0 else r.DiffVal(max(stage, 1));
444	        DiffVldIn <= r.VldDiff(0) when stage = 0 else r.VldDiff(max(stage, 1));
445	
446	        i_del : entity work.olo_base_delay
447	            generic map (
448	                Width_g       => cl_fix_width(DiffFmt_c),
449	                Delay_g       => Channels_g * DiffDelay_g,
450	                RstState_g    => true,
451	                Resource_g    => Resource_g,
452	                RamBehavior_g => RamBehavior_g,
453	                RamStyle_g    => RamStyle_g
454	            )
455	            port map (
456	                Clk      => Clk,
457	                Rst      => Rst,
458	
459	                -- Data
460	                In_Data  => DiffDelIn,
461	                In_Valid => DiffVldIn,
462	                Out_Data => DiffDel(stage)
463	            );
464	
465	    end generate;
466	
467	    -- *** Int-delays ***
468	    g_intdel_yes : if Channels_g > 1 generate
469	
470	        g_intdel : for stage in 0 to Order_g - 1 generate
471	
472	            i_del : entity work.olo_base_delay
473	                generic map (
474	                    Width_g       => cl_fix_width(AccuFmt_c),
475	                    Delay_g       => Channels_g - 1,
476	                    RstState_g    => true,
477	                    Resource_g    => Resource_g,
478	                    RamBehavior_g => RamBehavior_g,
479	                    RamStyle_g    => RamStyle_g
480	                )
481	                port map (
482	                    Clk      => Clk,
483	                    Rst      => Rst,
484	
485	                    -- Data
486	                    In_Data  => r.Accu(stage + 1),
487	                    In_Valid => r.VldAccu(stage),
488	                    Out_Data => IntDel(stage + 1)
489	                );
490	
491	        end generate;
492	
493	    end generate;
494	
495	end architecture;
496

