7	---------------------------------------------------------------------------------------------------
8	-- Description
9	---------------------------------------------------------------------------------------------------
10	-- This entity implements a CIC decimator. It supports one or multiple channels. On the input side
11	-- the channels are received in parallel (allowing one sample per cycle for every channel). On the output side
12	-- the channels are serialized in a time-division multiplexed way (TDM).
13	-- The decimation ratio can either be configurable or fixed.
14	--
15	-- Documentation:
16	-- https://github.com/open-logic/open-logic/blob/main/doc/fix/olo_fix_cic_dec_par_tdm.md
17	--
18	-- Note: The link points to the documentation of the latest release. If you
19	--       use an older version, the documentation might not match the code.
20	
21	---------------------------------------------------------------------------------------------------
22	-- Libraries
23	---------------------------------------------------------------------------------------------------
24	library ieee;
25	    use ieee.std_logic_1164.all;
26	    use ieee.numeric_std.all;
27	    use ieee.math_real.all;
28	
29	library work;
30	    use work.olo_base_pkg_math.all;
31	    use work.olo_base_pkg_string.all;
32	    use work.olo_base_pkg_array.all;
33	    use work.en_cl_fix_pkg.all;
34	    use work.olo_fix_pkg.all;
35	
36	---------------------------------------------------------------------------------------------------
37	-- Entity
38	---------------------------------------------------------------------------------------------------
39	entity olo_fix_cic_dec_par_tdm is
40	    generic (
41	        Channels_g        : positive := 1;
42	        Order_g           : positive range 2 to 32;
43	        Ratio_g           : positive;
44	        FixedRatio_g      : boolean  := true;
45	        DiffDelay_g       : positive := 1;
46	        InFmt_g           : string;
47	        OutFmt_g          : string;
48	        GainCorrCoefFmt_g : string   := "(0,1,16)";
49	        Round_g           : string   := FixRound_NonSymPos_c;
50	        Saturate_g        : string   := FixSaturate_Warn_c;
51	        -- Resource control generics
52	        RamBehavior_g     : string   := "RBW";
53	        RamStyle_g        : string   := "auto";
54	        Resource_g        : string   := "AUTO"
55	    );
56	    port (
57	        -- Control Signals
58	        Clk                              : in    std_logic;
59	        Rst                              : in    std_logic;
60	
61	        -- Configuration (only change when in reset!)
62	        Cfg_Ratio                        : in    std_logic_vector(log2ceil(Ratio_g)-1 downto 0);
63	        Cfg_Shift                        : in    std_logic_vector(7 downto 0);
64	        Cfg_GainCorr                     : in    std_logic_vector(fixFmtWidthFromStringTolerant(GainCorrCoefFmt_g) - 1 downto 0);
65	
66	        -- Input
67	        In_Valid                         : in    std_logic := '1';
68	        In_Data                          : in    std_logic_vector(fixFmtWidthFromString(InFmt_g)*Channels_g-1 downto 0);
69	
70	        -- Output
71	        Out_Valid                        : out   std_logic;
72	        Out_Data                         : out   std_logic_vector(fixFmtWidthFromString(OutFmt_g)-1 downto 0);
73	        Out_Last                         : out   std_logic
74	    );
75	end entity;
76	
77	---------------------------------------------------------------------------------------------------
78	-- Architecture section
79	---------------------------------------------------------------------------------------------------
80	
81	architecture rtl of olo_fix_cic_dec_par_tdm is
82	
83	    -- Constants
84	    constant EntityName_c : string := "olo_fix_cic_dec_par_tdm";
85	
86	    -- String upping
87	    constant GainCorrCoefFmtUpper_c : string := toUpper(GainCorrCoefFmt_g);
88	
89	    -- Formats
90	    constant InFmt_c           : FixFormat_t := cl_fix_format_from_string(InFmt_g);
91	    constant OutFmt_c          : FixFormat_t := cl_fix_format_from_string(OutFmt_g);
92	    constant GainCorrCoefFmt_c : FixFormat_t := fixFmtFromStringTolerant(GainCorrCoefFmtUpper_c);
93	
94	    -- Constants
95	    constant MaxCicGain_c    : real    := (real(Ratio_g)*real(DiffDelay_g))**real(Order_g);
96	    constant MaxCicAddBits_c : integer := log2ceil(MaxCicGain_c-0.1);
97	    -- ... WORKAROUND: Vivado does real calculations imprecisely. With the -0.1, wrong results are avoided.
98	    constant MaxShift_c      : integer     := MaxCicAddBits_c;
99	    constant AccuFmt_c       : FixFormat_t := (InFmt_c.S, InFmt_c.I+MaxCicAddBits_c, InFmt_c.F);
100	    constant DiffFmt_c       : FixFormat_t := (OutFmt_c.S, InFmt_c.I, OutFmt_c.F + Order_g + 1);
101	    constant GcInFmt_c       : FixFormat_t := (1, OutFmt_c.I, work.olo_base_pkg_math.min(OutFmt_c.F + 2, DiffFmt_c.F));
102	    constant SftFmt_c        : FixFormat_t := (AccuFmt_c.S, AccuFmt_c.I, max(AccuFmt_c.F, DiffFmt_c.F));
103	    constant RealGc_c        : real        := 2.0**real(MaxCicAddBits_c)/MaxCicGain_c;
104	
105	    constant FixedGc_c : std_logic_vector(cl_fix_width(GainCorrCoefFmt_c) - 1 downto 0) :=
106	        cl_fix_from_real(RealGc_c, GainCorrCoefFmt_c);
107	
108	    -- Types
109	    type AccuStage_t is array (natural range <>) of std_logic_vector(cl_fix_width(AccuFmt_c)-1 downto 0);
110	    type Accus_t is array (natural range <>) of AccuStage_t(0 to Channels_g-1);
111	    type Diff_t is array (natural range <>) of std_logic_vector(cl_fix_width(DiffFmt_c)-1 downto 0);
112	    type InputStage_t is array (natural range <>) of std_logic_vector(cl_fix_width(InFmt_c)-1 downto 0);
113	
114	    -- Two Process Method
115	    type TwoProcess_t is record
116	        -- GainCorr Registers
117	        GcCoef    : std_logic_vector(cl_fix_width(GainCorrCoefFmt_c)-1 downto 0);
118	        -- Accu Section
119	        Input_0   : InputStage_t(Channels_g-1 downto 0);
120	        VldAccu   : std_logic_vector(0 to Order_g);
121	        Accu      : Accus_t(1 to Order_g);
122	        Rcnt      : integer range 0 to Ratio_g-1;
123	        -- Diff Section
124	        VldParTdm : std_logic;
125	        VldDiff   : std_logic_vector(1 to Order_g);
126	        DiffVal   : Diff_t(1 to Order_g);
127	        -- Output
128	        OutChCnt  : natural range 0 to Channels_g-1;
129	        Outp      : std_logic_vector(cl_fix_width(OutFmt_c)-1 downto 0);
130	        Out_Valid : std_logic;
131	        Out_Last  : std_logic;
132	    end record;
133	
134	    signal r, r_next : TwoProcess_t;
135	
136	    -- Component Connection Signals
137	    signal ParTdmIn        : std_logic_vector(cl_fix_width(AccuFmt_c)*Channels_g-1 downto 0);
138	    signal ParTdmOut       : std_logic_vector(cl_fix_width(AccuFmt_c)-1 downto 0);
139	    signal ParTdmOut_Valid : std_logic;
140	    signal DiffIn_0        : std_logic_vector(cl_fix_width(DiffFmt_c)-1 downto 0);
141	    signal VldDiff_0       : std_logic;
142	    signal DiffDel         : Diff_t(0 to Order_g-1);
143	    signal ShiftVld        : std_logic;
144	    signal ShiftDataOut    : std_logic_vector(cl_fix_width(SftFmt_c)-1 downto 0);
145	
146	    -- Gain Correction Signals
147	    signal CompOut    : std_logic_vector(cl_fix_width(OutFmt_c) - 1 downto 0);
148	    signal CompOutVld : std_logic;
149	
150	begin
151	
152	    -----------------------------------------------------------------------------------------------
153	    -- Assertions
154	    -----------------------------------------------------------------------------------------------
155	    assert (GainCorrCoefFmtUpper_c = "NONE" or GainCorrCoefFmt_c.I = 1)
156	        report errorMessage(EntityName_c, "Gain correction coefficient format must have 1 integer bit (or be NONE)")
157	        severity failure;
158	    assert (GainCorrCoefFmtUpper_c = "NONE" or GainCorrCoefFmt_c.S = 0)
159	        report errorMessage(EntityName_c, "Gain correction coefficient format must be unsigned (or be NONE)")
160	        severity failure;
161	
162	    -----------------------------------------------------------------------------------------------
163	    -- Combinatorial Process
164	    -----------------------------------------------------------------------------------------------
165	    p_comb : process (all) is
166	        variable v       : TwoProcess_t;
167	        variable Ratio_v : std_logic_vector(Cfg_Ratio'range);
168	    begin
169	        -- hold variables stable
170	        v := r;
171	
172	        -- Ratio from port or constant
173	        if FixedRatio_g then
174	            Ratio_v := toUslv(Ratio_g - 1, Cfg_Ratio'length);
175	        else
176	            Ratio_v := Cfg_Ratio;
177	        end if;
178	
179	        -- *** Pipe Handling ***
180	        v.VldAccu(v.VldAccu'low+1 to v.VldAccu'high) := r.VldAccu(r.VldAccu'low to r.VldAccu'high-1);
181	        v.VldDiff(v.VldDiff'low+1 to v.VldDiff'high) := r.VldDiff(r.VldDiff'low to r.VldDiff'high-1);
182	
183	        -- *** Stage Accu 0 ***
184	        -- Input Registers
185	        v.VldAccu(0) := In_Valid;
186	
187	        for ch in 0 to Channels_g-1 loop
188	            v.Input_0(ch) := In_Data(cl_fix_width(InFmt_c)*(ch+1)-1 downto cl_fix_width(InFmt_c)*ch);
189	        end loop;
190	
191	        -- *** Stage Accu 1 ***
192	        -- First accumulator
193	        if r.VldAccu(0) = '1' then
194	
195	            for ch in 0 to Channels_g-1 loop
196	                v.Accu(1)(ch) := cl_fix_add(r.Accu(1)(ch), AccuFmt_c,
197	                                            r.Input_0(ch), InFmt_c,
198	                                            AccuFmt_c, Trunc_s, None_s);
199	            end loop;
200	
201	        end if;
202	
203	        -- *** Accumuator Stages (2 to Order) ***
204	        for stage in 1 to Order_g-1 loop
205	            if r.VldAccu(stage) = '1' then
206	
207	                for ch in 0 to Channels_g-1 loop
208	                    v.Accu(stage+1)(ch) := cl_fix_add(r.Accu(stage+1)(ch), AccuFmt_c,
209	                                                      r.Accu(stage)(ch), AccuFmt_c,
210	                                                      AccuFmt_c, Trunc_s, None_s);
211	                end loop;
212	
213	            end if;
214	        end loop;
215	
216	        -- *** Downsampling ***
217	        -- Decimate
218	        v.VldParTdm := '0';
219	        if r.VldAccu(Order_g-1) = '1' then
220	            if r.Rcnt = 0 then
221	                v.VldParTdm := '1';
222	                v.Rcnt      := to_integer(unsigned(Ratio_v));
223	            else
224	                v.Rcnt := r.Rcnt - 1;
225	            end if;
226	        end if;
227	
228	        -- *** Stage Diff 1 ***
229	        v.VldDiff(1) := VldDiff_0;
230	        -- First differentiator
231	        if VldDiff_0 = '1' then
232	            -- Differentiate
233	            v.DiffVal(1) := cl_fix_sub(DiffIn_0, DiffFmt_c,
234	                                       DiffDel(0), DiffFmt_c,
235	                                       DiffFmt_c, Trunc_s, None_s);
236	        end if;
237	
238	        -- *** Diff Stages ***
239	        -- Differentiators
240	        for stage in 1 to Order_g-1 loop
241	            if r.VldDiff(stage) = '1' then
242	                -- Differentiate
243	                v.DiffVal(stage+1) := cl_fix_sub(r.DiffVal(stage), DiffFmt_c,
244	                                                 DiffDel(stage), DiffFmt_c,
245	                                                 DiffFmt_c, Trunc_s, None_s);
246	            end if;
247	        end loop;
248	
249	        -- *** Gain Coefficient Register ***
250	        if GainCorrCoefFmtUpper_c /= "NONE" then
251	            -- *** Gain Coefficient Register ***
252	            v.GcCoef := Cfg_GainCorr;
253	        end if;
254	
255	        -- *** Output Assignment ***
256	        v.Outp      := CompOut;
257	        v.Out_Valid := CompOutVld;
258	
259	        -- *** Last calculation for TDM output ***
260	        v.Out_Last := '0';
261	        if v.Out_Valid = '1' then
262	            if r.OutChCnt = Channels_g - 1 then
263	                v.Out_Last := '1';
264	                v.OutChCnt := 0;
265	            else
266	                v.OutChCnt := r.OutChCnt + 1;
267	            end if;
268	        end if;
269	
270	        -- Apply to record
271	        r_next <= v;
272	
273	    end process;
274	
275	    -----------------------------------------------------------------------------------------------
276	    -- Output Assignment
277	    -----------------------------------------------------------------------------------------------
278	    Out_Valid <= r.Out_Valid;
279	    Out_Data  <= r.Outp;
280	    Out_Last  <= r.Out_Last;
281	
282	    -----------------------------------------------------------------------------------------------
283	    -- Sequential Process
284	    -----------------------------------------------------------------------------------------------
285	    p_seq : process (Clk) is
286	    begin
287	        if rising_edge(Clk) then
288	            r <= r_next;
289	            if Rst = '1' then
290	                r.VldAccu   <= (others => '0');
291	                r.Accu      <= (others => (others => (others => '0')));
292	                r.Rcnt      <= 0;
293	                r.VldDiff   <= (others => '0');
294	                r.OutChCnt  <= 0;
295	                r.Out_Valid <= '0';
296	                r.VldParTdm <= '0';
297	                r.Out_Last  <= '0';
298	            end if;
299	        end if;
300	    end process;
301	
302	    -----------------------------------------------------------------------------------------------
303	    -- Input TDM Validation
304	    -----------------------------------------------------------------------------------------------
305	    -- *** Gain Correction Chain ***
306	    g_gc : if GainCorrCoefFmtUpper_c /= "NONE" generate
307	        signal GcIn_0   : std_logic_vector(cl_fix_width(GcInFmt_c) - 1 downto 0);
308	        signal GcVld_0  : std_logic;
309	        signal GcCoef_0 : std_logic_vector(cl_fix_width(GainCorrCoefFmt_c) - 1 downto 0);
310	    begin
311	
312	        -- Resize
313	        i_gc_resize : entity work.olo_fix_resize
314	            generic map (
315	                AFmt_g      => to_string(DiffFmt_c),
316	                ResultFmt_g => to_string(GcInFmt_c),
317	                Round_g     => FixRound_Trunc_c,
318	                Saturate_g  => Saturate_g,
319	                RoundReg_g  => "auto",
320	                SatReg_g    => "auto"
321	            )
322	            port map (
323	                Clk        => Clk,
324	                Rst        => Rst,
325	                In_Valid   => r.VldDiff(Order_g),
326	                In_A       => r.DiffVal(Order_g),
327	                Out_Valid  => GcVld_0,
328	                Out_Result => GcIn_0
329	            );
330	
331	        -- Multiplier
332	        GcCoef_0 <= FixedGc_c when FixedRatio_g else r.GcCoef;
333	
334	        i_gc_mult : entity work.olo_fix_mult
335	            generic map (
336	                AFmt_g      => to_string(GcInFmt_c),
337	                BFmt_g      => to_string(GainCorrCoefFmt_c),
338	                ResultFmt_g => to_string(OutFmt_c),
339	                Round_g     => Round_g,
340	                Saturate_g  => Saturate_g,
341	                OpRegs_g    => 1,
342	                RoundReg_g  => "auto",
343	                SatReg_g    => "auto"
344	            )
345	            port map (
346	                Clk        => Clk,
347	                Rst        => Rst,
348	                In_Valid   => GcVld_0,
349	                In_A       => GcIn_0,
350	                In_B       => GcCoef_0,
351	                Out_Valid  => CompOutVld,
352	                Out_Result => CompOut
353	            );
354	
355	    end generate;
356	
357	    g_no_gc : if GainCorrCoefFmtUpper_c = "NONE" generate
358	
359	        i_resize_out : entity work.olo_fix_resize
360	            generic map (
361	                AFmt_g      => to_string(DiffFmt_c),
362	                ResultFmt_g => to_string(OutFmt_c),
363	                Round_g     => Round_g,
364	                Saturate_g  => Saturate_g,
365	                RoundReg_g  => "auto",
366	                SatReg_g    => "auto"
367	            )
368	            port map (
369	                Clk        => Clk,
370	                Rst        => Rst,
371	                In_Valid   => r.VldDiff(Order_g),
372	                In_A       => r.DiffVal(Order_g),
373	                Out_Valid  => CompOutVld,
374	                Out_Result => CompOut
375	            );
376	
377	    end generate;
378	
379	    -- *** Parallel to TDM conversion before diff-stages ***
380	    g_partdmin : for ch in 0 to Channels_g-1 generate
381	        ParTdmIn(cl_fix_width(AccuFmt_c)*(ch+1)-1 downto cl_fix_width(AccuFmt_c)*ch) <= r.Accu(Order_g)(ch);
382	    end generate;
383	
384	    i_partdm : entity work.olo_base_wconv_xn2n
385	        generic map (
386	            InWidth_g  => Channels_g * cl_fix_width(AccuFmt_c),
387	            OutWidth_g => cl_fix_width(AccuFmt_c)
388	        )
389	        port map (
390	            Clk       => Clk,
391	            Rst       => Rst,
392	            In_Valid  => r.VldParTdm,
393	            In_Data   => ParTdmIn,
394	            Out_Valid => ParTdmOut_Valid,
395	            Out_Data  => ParTdmOut
396	        );
397	
398	    -- *** Dynamic Shifter ***
399	    -- For configurable ratio, the shift is dynamic. For fixed ratio it is fixed.
400	    g_shift_conf : if not FixedRatio_g generate
401	        signal ShiftSel    : std_logic_vector(log2ceil(MaxShift_c + 1) - 1 downto 0);
402	        signal ShiftDataIn : std_logic_vector(cl_fix_width(SftFmt_c) - 1 downto 0);
403	    begin
404	
405	        ShiftSel    <= Cfg_Shift(ShiftSel'range);
406	        ShiftDataIn <= cl_fix_resize(ParTdmOut, AccuFmt_c, SftFmt_c, Trunc_s, None_s);
407	
408	        i_sft : entity work.olo_base_dyn_sft
409	            generic map (
410	                Direction_g       => "RIGHT",
411	                SelBitsPerStage_g => 4,
412	                MaxShift_g        => MaxShift_c,
413	                Width_g           => cl_fix_width(SftFmt_c),
414	                SignExtend_g      => true
415	            )
416	            port map (
417	                Clk       => Clk,
418	                Rst       => Rst,
419	                In_Valid  => ParTdmOut_Valid,
420	                In_Shift  => ShiftSel,
421	                In_Data   => ShiftDataIn,
422	                Out_Valid => ShiftVld,
423	                Out_Data  => ShiftDataOut
424	            );
425	
426	    end generate;
427	
428	    g_shift_fixed : if FixedRatio_g generate
429	        -- Shift is combinatorial because it is pure wiring
430	        ShiftVld     <= ParTdmOut_Valid;
431	        ShiftDataOut <= cl_fix_shift(ParTdmOut, AccuFmt_c, -MaxShift_c, SftFmt_c, Trunc_s, None_s);
432	    end generate;
433	
434	    VldDiff_0 <= ShiftVld;
435	    DiffIn_0  <= cl_fix_resize(ShiftDataOut, SftFmt_c, DiffFmt_c, Trunc_s, None_s);
436	
437	    -- *** Diff-delays ***
438	    g_diffdel : for stage in 0 to Order_g-1 generate
439	        signal DiffDelIn : std_logic_vector(cl_fix_width(DiffFmt_c)-1 downto 0);
440	        signal DiffVldIn : std_logic;
441	    begin
442	        DiffDelIn <= DiffIn_0 when stage = 0 else r.DiffVal(max(stage, 1));
443	        DiffVldIn <= VldDiff_0 when stage = 0 else r.VldDiff(max(stage, 1));
444	
445	        i_del : entity work.olo_base_delay
446	            generic map (
447	                Width_g       => cl_fix_width(DiffFmt_c),
448	                Delay_g       => Channels_g * DiffDelay_g,
449	                RstState_g    => true,
450	                Resource_g    => Resource_g,
451	                RamBehavior_g => RamBehavior_g,
452	                RamStyle_g    => RamStyle_g
453	            )
454	            port map (
455	                Clk      => Clk,
456	                Rst      => Rst,
457	
458	                -- Data
459	                In_Data  => DiffDelIn,
460	                In_Valid => DiffVldIn,
461	                Out_Data => DiffDel(stage)
462	            );
463	
464	    end generate;
465	
466	end architecture;
467

